// headless:和弦谱 string → parse → 可选 transpose → format 成 HTML/Text 字符串(无 DOM 足迹)
import { ChordProParser, ChordsOverWordsParser, UltimateGuitarParser, HtmlDivFormatter, HtmlTableFormatter, TextFormatter } from 'https://cdn.jsdelivr.net/npm/chordsheetjs@15.5.2/+esm';
const Parser = { 'chordpro': ChordProParser, 'chords-over-words': ChordsOverWordsParser, 'ultimate-guitar': UltimateGuitarParser }[data.dialect ?? 'chordpro'];
let song = new Parser().parse(data.source);
if (data.transpose) song = song.transpose(data.transpose);
const Formatter = { 'html-div': HtmlDivFormatter, 'html-table': HtmlTableFormatter, 'text': TextFormatter }[data.format ?? 'html-div'];
const markup = new Formatter().format(song); // string;消费方插入(HTML 格式另加 CSS)
